-- Corrections de Justine (textes des fiches)
update public.species set note='« sp1 » signifie : espèce repérée mais pas encore décrite officiellement, en attente d''un vrai nom (il existe aussi sp2 et sp3). Bora Bora a encore des secrets à livrer.', description='["Corps blanc nacré, taches brun-or, liseré bleu marine","Rosette branchiale bleu-violet","Se nourrit d''éponges"]'::jsonb where id='chromodoris-sp1';
update public.species set note='« sp3 » signifie : espèce repérée mais pas encore décrite officiellement — la 3ᵉ de ce genre en attente d''un vrai nom (il existe aussi sp1 et sp2). Il reste des découvertes à faire à Bora Bora.', description='["Corps blanc-bleu pâle strié de lignes bleu marine","Rhinophores orange vif","Se nourrit d''éponges"]'::jsonb where id='chromodoris-sp3';
update public.species set note='Observés par dizaines un matin à Bora Bora avec Dive N'' Smile — un événement encore peu documenté en Polynésie française.', description='["Corps blanc translucide, pois rouge vif, liseré orange","Prédateur — se nourrit d''autres nudibranches","En reproduction : agrégations de dizaines d''individus"]'::jsonb where id='gymnodoris-ceylonica';
update public.species set note='Une des plus grandes du récif — même les plongeurs qui ne regardent pas le fond la remarquent !', description='["Corps jaune-crème, taches noires, liseré bleu-violet","Rosette branchiale bien développée","Indo-Pacifique, fréquente en Polynésie française"]'::jsonb where id='goniobranchus-kuniei';
